import{_ as t,W as l,X as s,Z as e,$ as n,a0 as o,a1 as i,D as d}from"./framework-c9619a7b.js";const r={},c=i('<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523204215.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>Conda是一个流行的开源软件包管理系统和环境管理系统，用于管理多个软件包和其依赖关系。Conda可以在多个操作系统上使用，如Windows、macOS和Linux，并且可以管理多种编程语言的软件包，如Python、R、Julia等。Conda提供了一个命令行界面，也可以通过Anaconda Navigator等图形用户界面进行管理。</p><p>Conda的主要特点包括：</p><ul><li><p><strong>软件包管理</strong>：Conda可以管理多个软件包及其依赖关系，可以安装、更新、卸载和查看软件包信息，方便用户管理和使用软件包。</p></li><li><p><strong>环境管理</strong>：Conda可以创建、激活和删除多个环境，每个环境可以拥有自己的软件包和依赖关系，可以方便地管理不同项目的依赖关系。</p></li><li><p><strong>跨平台支持</strong>：Conda可以在多个操作系统上使用，如Windows、macOS和Linux，并且可以管理多种编程语言的软件包，如Python、R、Julia等，方便用户在不同平台和编程语言之间进行切换和管理。</p></li><li><p><strong>自动依赖解决</strong>：Conda可以自动解决软件包之间的依赖关系，确保安装的软件包和其依赖的软件包版本兼容，并且不会产生冲突或错误。</p></li><li><p><strong>离线安装</strong>：Conda支持离线安装，可以将软件包和依赖关系打包成一个离线安装包，方便用户在没有网络连接或有限带宽的环境中安装软件包。</p></li><li><p><strong>快速安装</strong>：Conda的软件包和依赖关系都是预编译的，可以加快软件包的安装和使用速度。</p></li><li><p><strong>免费开源</strong>：Conda是一款开源的软件，可以免费使用和分发，没有任何使用限制和费用。</p></li></ul><p>总之，Conda是一个流行的开源软件包管理系统和环境管理系统，可以方便地管理多个软件包和其依赖关系，支持跨平台使用和多种编程语言，具有自动依赖解决、离线安装、快速安装等特点。使用Conda可以通过命令行或图形用户界面进行软件包和环境管理，方便用户进行项目开发和科学计算。</p><h2 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h2><h3 id="windows" tabindex="-1"><a class="header-anchor" href="#windows" aria-hidden="true">#</a> Windows</h3><ol><li>下载安装包</li></ol>',9),p={href:"https://docs.conda.io/en/latest/miniconda.html",target:"_blank",rel:"noopener noreferrer"},g=i('<p>选择适合自己系统版本的进行安装。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523194825.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="2"><li>配置环境变量</li></ol><p>打开环境变量设置，找到系统<code>PATH</code>环境变量进行编辑</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523194635.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>将下面红框标注的路径添加到<strong>系统</strong><code>PATH</code>环境变量中(仅供参考，具体路径根据你的安装路径确定)，这些目录下包含了<code>python.exe</code>、<code>conda.exe</code>等二进制执行文件。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523194419.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="3"><li>设置权限(可选)</li></ol>',8),h={href:"https://learn.microsoft.com/zh-cn/powershell/module/microsoft.powershell.core/about/about_execution_policies?view=powershell-7.3",target:"_blank",rel:"noopener noreferrer"},u=i(`<p>由于conda初始化时候会执行脚本，</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523193323.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>而系统默认执行策略为<code>Restricted</code>，该策略下是不允许执行脚本的，所以会出现上面红色错误(如果你没有这个问题，可跳过此步骤)。</p><p>解决方法： 通过以管理员权限打开终端，输入下面命令修改执行策略来允许运行脚本。</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token comment"># 查看当前执行策略</span>
<span class="token function">Get-ExecutionPolicy</span>

<span class="token comment"># 修改策略(管理员权限)</span>
<span class="token function">Set-ExecutionPolicy</span> <span class="token operator">-</span>ExecutionPolicy RemoteSigned
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523193555.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>两种策略对比：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523193924.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="4"><li>初始化</li></ol><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code>conda init powershell 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523194119.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>重新启动终端，可以看到已经可以识别python环境名称了。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523194234.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="ubuntu" tabindex="-1"><a class="header-anchor" href="#ubuntu" aria-hidden="true">#</a> Ubuntu</h2><p>xx</p><h1 id="使用" tabindex="-1"><a class="header-anchor" href="#使用" aria-hidden="true">#</a> 使用</h1><h2 id="镜像源配置" tabindex="-1"><a class="header-anchor" href="#镜像源配置" aria-hidden="true">#</a> 镜像源配置</h2>`,17),m={href:"https://mirrors.tuna.tsinghua.edu.cn/help/anaconda/",target:"_blank",rel:"noopener noreferrer"},b=i(`<p>方法：用国内源覆盖<code>$HOME/.condarc</code>的内容。</p><blockquote><p>注意: windows用户需要先通过命令<code>conda config --set show_channel_urls yes</code>生成<code>.condarc</code>文件再进行配置。</p></blockquote><h2 id="环境管理" tabindex="-1"><a class="header-anchor" href="#环境管理" aria-hidden="true">#</a> 环境管理</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 查看已有环境</span>
conda <span class="token function">env</span> list

<span class="token comment"># 导出环境</span>
xx

<span class="token comment"># 迁移环境</span>
xx
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,4);function f(v,_){const a=d("ExternalLinkIcon");return l(),s("div",null,[c,e("p",null,[n("下载地址："),e("a",p,[n("https://docs.conda.io/en/latest/miniconda.html"),o(a)])]),g,e("blockquote",null,[e("p",null,[n("参考："),e("a",h,[n("https://learn.microsoft.com/zh-cn/powershell/module/microsoft.powershell.core/about/about_execution_policies?view=powershell-7.3"),o(a)])])]),u,e("ul",null,[e("li",null,[n("清华源："),e("a",m,[n("https://mirrors.tuna.tsinghua.edu.cn/help/anaconda/"),o(a)])])]),b])}const k=t(r,[["render",f],["__file","Conda安装与使用教程.html.vue"]]);export{k as default};
